   126→protected:
   127→  class WatchImpl : public Envoy::Config::GrpcMuxWatch {
   128→  public:
   129→    WatchImpl(const std::string& type_url, Watch* watch, GrpcMuxImpl& parent,
   130→              const SubscriptionOptions& options)
   131→        : type_url_(type_url), watch_(watch), parent_(parent), options_(options) {}
   132→
   133→    ~WatchImpl() override { remove(); }
   134→
   135→    void remove() {
   136→      if (watch_) {
   137→        parent_.removeWatch(type_url_, watch_);
   138→        watch_ = nullptr;
   139→      }
   140→    }
   141→
   142→    void update(const absl::flat_hash_set<std::string>& resources) override {
   143→      parent_.updateWatch(type_url_, watch_, resources, options_);
   144→    }
   145→
   146→  private:
   147→    const std::string type_url_;
   148→    Watch* watch_;
   149→    GrpcMuxImpl& parent_;
   150→    const SubscriptionOptions options_;
   151→  };
