   180→  // is deprecated.
   181→  std::unique_ptr<GrpcStreamInterface<RQ, RS>>
   182→  createGrpcStreamObject(Grpc::RawAsyncClientSharedPtr&& async_client,
   183→                         Grpc::RawAsyncClientSharedPtr&& failover_async_client,
   184→                         const Protobuf::MethodDescriptor& service_method, Stats::Scope& scope,
   185→                         BackOffStrategyPtr&& backoff_strategy,
   186→                         const RateLimitSettings& rate_limit_settings);
   187→
   188→  // Checks whether external conditions allow sending a DeltaDiscoveryRequest. (Does not check
   189→  // whether we *want* to send a (Delta)DiscoveryRequest).
   190→  bool canSendDiscoveryRequest(const std::string& type_url);
   191→
   192→  // Checks whether we have something to say in a (Delta)DiscoveryRequest, which can be an ACK
   193→  // and/or a subscription update. (Does not check whether we *can* send that
   194→  // (Delta)DiscoveryRequest). Returns the type_url we should send the DeltaDiscoveryRequest for (if
   195→  // any). First, prioritizes ACKs over non-ACK subscription interest updates. Then, prioritizes
   196→  // non-ACK updates in the order the various types of subscriptions were activated (as tracked by
   197→  // subscription_ordering_).
   198→  absl::optional<std::string> whoWantsToSendDiscoveryRequest();
   199→
   200→  // Invoked when dynamic context parameters change for a resource type.
   201→  void onDynamicContextUpdate(absl::string_view resource_type_url);
   202→
   203→  Event::Dispatcher& dispatcher_;
   204→  // Multiplexes the stream to the primary and failover sources.
   205→  // TODO(adisuissa): Once envoy.restart_features.xds_failover_support is deprecated,
   206→  // convert from unique_ptr<GrpcStreamInterface> to GrpcMuxFailover directly.
   207→  std::unique_ptr<GrpcStreamInterface<RQ, RS>> grpc_stream_;
   208→
   209→  // Resource (N)ACKs we're waiting to send, stored in the order that they should be sent in. All
   210→  // of our different resource types' ACKs are mixed together in this queue. See class for
   211→  // description of how it interacts with pause() and resume().
   212→  PausableAckQueue pausable_ack_queue_;
   213→
   214→  // Makes SubscriptionStates, to be held in the subscriptions_ map. Whether this GrpcMux is doing
   215→  // delta or state of the world xDS is determined by which concrete subclass this variable gets.
   216→  std::unique_ptr<F> subscription_state_factory_;
   217→
   218→  // Map key is type_url.
   219→  // Only addWatch() should insert into these maps.
   220→  absl::flat_hash_map<std::string, std::unique_ptr<S>> subscriptions_;
   221→  absl::flat_hash_map<std::string, std::unique_ptr<WatchMap>> watch_maps_;
   222→
   223→  // Determines the order of initial discovery requests. (Assumes that subscriptions are added
   224→  // to this GrpcMux in the order of Envoy's dependency ordering).
   225→  std::list<std::string> subscription_ordering_;
   226→
   227→  // Whether to enable the optimization of only including the node field in the very first
   228→  // discovery request in an xDS gRPC stream (really just one: *not* per-type_url).
   229→  const bool skip_subsequent_node_;
   230→
   231→  // State to help with skip_subsequent_node's logic.
   232→  bool any_request_sent_yet_in_current_stream_{};
   233→
   234→  // Used to populate the (Delta)DiscoveryRequest's node field. That field is the same across
   235→  // all type_urls, and moreover, the 'skip_subsequent_node' logic needs to operate across all
   236→  // the type_urls. So, while the SubscriptionStates populate every other field of these messages,
   237→  // this one is up to GrpcMux.
   238→  const LocalInfo::LocalInfo& local_info_;
   239→  Common::CallbackHandlePtr dynamic_update_callback_handle_;
   240→  CustomConfigValidatorsPtr config_validators_;
   241→  XdsConfigTrackerOptRef xds_config_tracker_;
   242→  XdsResourcesDelegateOptRef xds_resources_delegate_;
   243→  EdsResourcesCachePtr eds_resources_cache_;
   244→  const std::string target_xds_authority_;
   245→
   246→  // Used to track whether initial_resource_versions should be populated on the
   247→  // next reconnection.
   248→  bool should_send_initial_resource_versions_{true};
   249→
   250→  bool started_{false};
   251→  // True iff Envoy is shutting down; no messages should be sent on the `grpc_stream_` when this is
   252→  // true because it may contain dangling pointers.
   253→  std::atomic<bool> shutdown_{false};
   254→};
