   357→void GrpcMuxImpl::onDiscoveryResponse(
   358→    std::unique_ptr<envoy::service::discovery::v3::DiscoveryResponse>&& message,
   359→    ControlPlaneStats& control_plane_stats) {
   360→  const std::string type_url = message->type_url();
   361→  ENVOY_LOG(debug, "Received gRPC message for {} at version {}", type_url, message->version_info());
   362→
   363→  if (api_state_.count(type_url) == 0) {
   364→    // TODO(yuval-k): This should never happen. consider dropping the stream as this is a
   365→    // protocol violation
   366→    ENVOY_LOG(warn, "Ignoring the message for type URL {} as it has no current subscribers.",
   367→              type_url);
   368→    return;
   369→  }
   370→
   371→  ApiState& api_state = apiStateFor(type_url);
   372→
   373→  if (message->has_control_plane()) {
   374→    control_plane_stats.identifier_.set(message->control_plane().identifier());
   375→
   376→    if (message->control_plane().identifier() != api_state.control_plane_identifier_) {
   377→      api_state.control_plane_identifier_ = message->control_plane().identifier();
   378→      ENVOY_LOG(debug, "Receiving gRPC updates for {} from {}", type_url,
   379→                api_state.control_plane_identifier_);
   380→    }
   381→  }
   382→
   383→  if (api_state.watches_.empty()) {
   384→    // update the nonce as we are processing this response.
   385→    api_state.request_.set_response_nonce(message->nonce());
   386→    if (message->resources().empty()) {
   387→      // No watches and no resources. This can happen when envoy unregisters from a
   388→      // resource that's removed from the server as well. For example, a deleted cluster
   389→      // triggers un-watching the ClusterLoadAssignment watch, and at the same time the
   390→      // xDS server sends an empty list of ClusterLoadAssignment resources. we'll accept
   391→      // this update. no need to send a discovery request, as we don't watch for anything.
   392→      api_state.request_.set_version_info(message->version_info());
   393→    } else {
   394→      // No watches and we have resources - this should not happen. send a NACK (by not
   395→      // updating the version).
   396→      ENVOY_LOG(warn, "Ignoring unwatched type URL {}", type_url);
   397→      queueDiscoveryRequest(type_url);
   398→    }
   399→    return;
   400→  }
   401→  ScopedResume same_type_resume;
   402→  // We pause updates of the same type. This is necessary for SotW and GrpcMuxImpl, since unlike
   403→  // delta and NewGRpcMuxImpl, independent watch additions/removals trigger updates regardless of
   404→  // the delta state. The proper fix for this is to converge these implementations,
   405→  // see https://github.com/envoyproxy/envoy/issues/11477.
   406→  same_type_resume = pause(type_url);
   407→  TRY_ASSERT_MAIN_THREAD {
   408→    std::vector<DecodedResourcePtr> resources;
   409→    OpaqueResourceDecoder& resource_decoder = *api_state.watches_.front()->resource_decoder_;
   410→
   411→    for (const auto& resource : message->resources()) {
   412→      // TODO(snowp): Check the underlying type when the resource is a Resource.
   413→      if (!resource.Is<envoy::service::discovery::v3::Resource>() &&
   414→          type_url != resource.type_url()) {
   415→        throwEnvoyExceptionOrPanic(
   416→            fmt::format("{} does not match the message-wide type URL {} in DiscoveryResponse {}",
   417→                        resource.type_url(), type_url, message->DebugString()));
   418→      }
   419→
   420→      auto decoded_resource = THROW_OR_RETURN_VALUE(
   421→          DecodedResourceImpl::fromResource(resource_decoder, resource, message->version_info()),
   422→          DecodedResourceImplPtr);
   423→
   424→      if (!isHeartbeatResource(type_url, *decoded_resource)) {
   425→        resources.emplace_back(std::move(decoded_resource));
   426→      }
   427→    }
   428→
   429→    processDiscoveryResources(resources, api_state, type_url, message->version_info(),
   430→                              /*call_delegate=*/true);
   431→
   432→    // Processing point when resources are successfully ingested.
   433→    if (xds_config_tracker_.has_value()) {
   434→      xds_config_tracker_->onConfigAccepted(type_url, resources);
   435→    }
   436→  }
   437→  END_TRY
   438→  CATCH(const EnvoyException& e, {
   439→    for (auto watch : api_state.watches_) {
   440→      watch->callbacks_.onConfigUpdateFailed(
   441→          Envoy::Config::ConfigUpdateFailureReason::UpdateRejected, &e);
   442→    }
   443→    ::google::rpc::Status* error_detail = api_state.request_.mutable_error_detail();
   444→    error_detail->set_code(Grpc::Status::WellKnownGrpcStatus::Internal);
   445→    error_detail->set_message(Config::Utility::truncateGrpcStatusMessage(e.what()));
   446→
   447→    // Processing point when there is any exception during the parse and ingestion process.
   448→    if (xds_config_tracker_.has_value()) {
   449→      xds_config_tracker_->onConfigRejected(*message, error_detail->message());
   450→    }
   451→  });
   452→  api_state.previously_fetched_data_ = true;
   453→  api_state.request_.set_response_nonce(message->nonce());
   454→  ASSERT(api_state.paused());
   455→  queueDiscoveryRequest(type_url);
   456→}
   457→
   458→void GrpcMuxImpl::processDiscoveryResources(const std::vector<DecodedResourcePtr>& resources,
   459→                                            ApiState& api_state, const std::string& type_url,
   460→                                            const std::string& version_info,
   461→                                            const bool call_delegate) {
   462→  ASSERT_IS_MAIN_OR_TEST_THREAD();
   463→  // To avoid O(n^2) explosion (e.g. when we have 1000s of EDS watches), we
   464→  // build a map here from resource name to resource and then walk watches_.
   465→  // We have to walk all watches (and need an efficient map as a result) to
   466→  // ensure we deliver empty config updates when a resource is dropped. We make the map ordered
   467→  // for test determinism.
   468→  absl::btree_map<std::string, DecodedResourceRef> resource_ref_map;
   469→  std::vector<DecodedResourceRef> all_resource_refs;
   470→
   471→  const auto scoped_ttl_update = api_state.ttl_.scopedTtlUpdate();
   472→
   473→  for (const auto& resource : resources) {
   474→    if (resource->ttl()) {
   475→      api_state.ttl_.add(*resource->ttl(), resource->name());
   476→    } else {
   477→      api_state.ttl_.clear(resource->name());
   478→    }
   479→
   480→    all_resource_refs.emplace_back(*resource);
   481→    if (XdsResourceIdentifier::hasXdsTpScheme(resource->name())) {
   482→      // Sort the context params of an xdstp resource, so we can compare them easily.
   483→      auto resource_or_error = XdsResourceIdentifier::decodeUrn(resource->name());
   484→      THROW_IF_NOT_OK_REF(resource_or_error.status());
   485→      xds::core::v3::ResourceName xdstp_resource = resource_or_error.value();
   486→      XdsResourceIdentifier::EncodeOptions options;
   487→      options.sort_context_params_ = true;
   488→      resource_ref_map.emplace(XdsResourceIdentifier::encodeUrn(xdstp_resource, options),
   489→                               *resource);
   490→    } else {
   491→      resource_ref_map.emplace(resource->name(), *resource);
   492→    }
   493→  }
   494→
   495→  // Execute external config validators if there are any watches.
   496→  if (!api_state.watches_.empty()) {
   497→    config_validators_->executeValidators(type_url, resources);
   498→  }
   499→
   500→  for (auto watch : api_state.watches_) {
   501→    // onConfigUpdate should be called in all cases for single watch xDS (Cluster and
   502→    // Listener) even if the message does not have resources so that update_empty stat
   503→    // is properly incremented and state-of-the-world semantics are maintained.
   504→    if (watch->resources_.empty()) {
   505→      THROW_IF_NOT_OK(watch->callbacks_.onConfigUpdate(all_resource_refs, version_info));
   506→      continue;
   507→    }
   508→    std::vector<DecodedResourceRef> found_resources;
   509→    for (const auto& watched_resource_name : watch->resources_) {
   510→      // Look for a singleton subscription.
   511→      auto it = resource_ref_map.find(watched_resource_name);
   512→      if (it != resource_ref_map.end()) {
   513→        found_resources.emplace_back(it->second);
   514→      } else if (isXdsTpWildcard(watched_resource_name)) {
   515→        // See if the resources match the xdstp wildcard subscription.
   516→        // Note: although it is unlikely that Envoy will need to support a resource that is mapped
   517→        // to both a singleton and collection watch, this code still supports this use case.
   518→        // TODO(abeyad): This could be made more efficient, e.g. by pre-computing and having a map
   519→        // entry for each wildcard watch.
   520→        for (const auto& resource_ref_it : resource_ref_map) {
   521→          if (XdsResourceIdentifier::hasXdsTpScheme(resource_ref_it.first) &&
   522→              convertToWildcard(resource_ref_it.first) == watched_resource_name) {
   523→            found_resources.emplace_back(resource_ref_it.second);
   524→          }
   525→        }
   526→      }
   527→    }
   528→
   529→    // onConfigUpdate should be called only on watches(clusters/listeners) that have
   530→    // updates in the message for EDS/RDS.
   531→    if (!found_resources.empty()) {
   532→      THROW_IF_NOT_OK(watch->callbacks_.onConfigUpdate(found_resources, version_info));
