   345→                type_url, api_state.pauses_);
   346→      ASSERT(api_state.paused());
   347→
   348→      if (--api_state.pauses_ == 0 && api_state.pending_ && api_state.subscribed_) {
   349→        ENVOY_LOG(debug, "Resuming discovery requests for {}", type_url);
