    86→std::unique_ptr<GrpcStreamInterface<envoy::service::discovery::v3::DiscoveryRequest,
    87→                                    envoy::service::discovery::v3::DiscoveryResponse>>
    88→GrpcMuxImpl::createGrpcStreamObject(Grpc::RawAsyncClientSharedPtr&& async_client,
    89→                                    Grpc::RawAsyncClientSharedPtr&& failover_async_client,
    90→                                    const Protobuf::MethodDescriptor& service_method,
    91→                                    Stats::Scope& scope, BackOffStrategyPtr&& backoff_strategy,
    92→                                    const RateLimitSettings& rate_limit_settings) {
    93→  if (Runtime::runtimeFeatureEnabled("envoy.restart_features.xds_failover_support")) {
    94→    return std::make_unique<GrpcMuxFailover<envoy::service::discovery::v3::DiscoveryRequest,
    95→                                            envoy::service::discovery::v3::DiscoveryResponse>>(
    96→        /*primary_stream_creator=*/
    97→        [&async_client, &service_method, &dispatcher = dispatcher_, &scope, &backoff_strategy,
    98→         &rate_limit_settings](
    99→            GrpcStreamCallbacks<envoy::service::discovery::v3::DiscoveryResponse>* callbacks)
   100→            -> GrpcStreamInterfacePtr<envoy::service::discovery::v3::DiscoveryRequest,
   101→                                      envoy::service::discovery::v3::DiscoveryResponse> {
   102→          return std::make_unique<GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
   103→                                             envoy::service::discovery::v3::DiscoveryResponse>>(
   104→              callbacks, std::move(async_client), service_method, dispatcher, scope,
   105→              std::move(backoff_strategy), rate_limit_settings,
   106→              GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
   107→                         envoy::service::discovery::v3::DiscoveryResponse>::ConnectedStateValue::
   108→                  FirstEntry);
   109→        },
   110→        /*failover_stream_creator=*/
   111→        failover_async_client
   112→            ? absl::make_optional(
   113→                  [&failover_async_client, &service_method, &dispatcher = dispatcher_, &scope,
   114→                   &rate_limit_settings](
   115→                      GrpcStreamCallbacks<envoy::service::discovery::v3::DiscoveryResponse>*
   116→                          callbacks)
   117→                      -> GrpcStreamInterfacePtr<envoy::service::discovery::v3::DiscoveryRequest,
   118→                                                envoy::service::discovery::v3::DiscoveryResponse> {
   119→                    return std::make_unique<
   120→                        GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
   121→                                   envoy::service::discovery::v3::DiscoveryResponse>>(
   122→                        callbacks, std::move(failover_async_client), service_method, dispatcher,
   123→                        scope,
   124→                        // TODO(adisuissa): the backoff strategy for the failover should
   125→                        // be the same as the primary source.
   126→                        std::make_unique<FixedBackOffStrategy>(
   127→                            GrpcMuxFailover<envoy::service::discovery::v3::DiscoveryRequest,
   128→                                            envoy::service::discovery::v3::DiscoveryResponse>::
   129→                                DefaultFailoverBackoffMilliseconds),
   130→                        rate_limit_settings,
   131→                        GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
   132→                                   envoy::service::discovery::v3::DiscoveryResponse>::
   133→                            ConnectedStateValue::SecondEntry);
   134→                  })
   135→            : absl::nullopt,
   136→        /*grpc_mux_callbacks=*/*this,
   137→        /*dispatch=*/dispatcher_);
   138→  }
   139→  return std::make_unique<GrpcStream<envoy::service::discovery::v3::DiscoveryRequest,
   140→                                     envoy::service::discovery::v3::DiscoveryResponse>>(
   141→      this, std::move(async_client), service_method, dispatcher_, scope,
   142→      std::move(backoff_strategy), rate_limit_settings,
   143→      GrpcStream<
   144→          envoy::service::discovery::v3::DiscoveryRequest,
   145→          envoy::service::discovery::v3::DiscoveryResponse>::ConnectedStateValue::FirstEntry);
   146→}
