   166→  started_ = true;
   167→  grpc_stream_->establishNewStream();
   168→}
   169→
   170→void GrpcMuxImpl::sendDiscoveryRequest(absl::string_view type_url) {
   171→  if (shutdown_) {
   172→    return;
   173→  }
   174→
   175→  ApiState& api_state = apiStateFor(type_url);
   176→  auto& request = api_state.request_;
   177→  request.mutable_resource_names()->Clear();
   178→
   179→  // Maintain a set to avoid dupes.
   180→  absl::node_hash_set<std::string> resources;
   181→  for (const auto* watch : api_state.watches_) {
   182→    for (const std::string& resource : watch->resources_) {
   183→      if (!resources.contains(resource)) {
   184→        resources.emplace(resource);
   185→        request.add_resource_names(resource);
   186→      }
   187→    }
   188→  }
   189→
   190→  if (api_state.must_send_node_ || !skip_subsequent_node_ || first_stream_request_) {
   191→    // Node may have been cleared during a previous request.
   192→    request.mutable_node()->CopyFrom(local_info_.node());
   193→    api_state.must_send_node_ = false;
   194→  } else {
   195→    request.clear_node();
   196→  }
   197→  ENVOY_LOG(trace, "Sending DiscoveryRequest for {}: {}", type_url, request.ShortDebugString());
   198→  grpc_stream_->sendMessage(request);
   199→  first_stream_request_ = false;
   200→
   201→  // clear error_detail after the request is sent if it exists.
   202→  if (apiStateFor(type_url).request_.has_error_detail()) {
   203→    apiStateFor(type_url).request_.clear_error_detail();
   204→  }
   205→}
   206→
   207→void GrpcMuxImpl::clearNonce() {
   208→  // Iterate over all api_states (for each type_url), and clear its nonce.
   209→  for (auto& [type_url, api_state] : api_state_) {
   210→    if (api_state) {
   211→      api_state->request_.clear_response_nonce();
   212→    }
   213→  }
   214→}
   215→
   216→void GrpcMuxImpl::loadConfigFromDelegate(const std::string& type_url,
   217→                                         const absl::flat_hash_set<std::string>& resource_names) {
   218→  if (!xds_resources_delegate_.has_value()) {
   219→    return;
   220→  }
   221→  ApiState& api_state = apiStateFor(type_url);
   222→  if (api_state.watches_.empty()) {
   223→    // No watches, so exit without loading config from storage.
   224→    return;
   225→  }
   226→
   227→  const XdsConfigSourceId source_id{target_xds_authority_, type_url};
   228→  TRY_ASSERT_MAIN_THREAD {
   229→    std::vector<envoy::service::discovery::v3::Resource> resources =
   230→        xds_resources_delegate_->getResources(source_id, resource_names);
   231→    if (resources.empty()) {
   232→      // There are no persisted resources, so nothing to process.
   233→      return;
   234→    }
   235→
   236→    std::vector<DecodedResourcePtr> decoded_resources;
   237→    OpaqueResourceDecoder& resource_decoder = *api_state.watches_.front()->resource_decoder_;
   238→    std::string version_info;
   239→    for (const auto& resource : resources) {
   240→      if (version_info.empty()) {
   241→        version_info = resource.version();
   242→      } else {
   243→        ASSERT(resource.version() == version_info);
   244→      }
   245→
   246→      TRY_ASSERT_MAIN_THREAD {
   247→        decoded_resources.emplace_back(
   248→            std::make_unique<DecodedResourceImpl>(resource_decoder, resource));
   249→      }
   250→      END_TRY
   251→      CATCH(const EnvoyException& e,
   252→            { xds_resources_delegate_->onResourceLoadFailed(source_id, resource.name(), e); });
   253→    }
   254→
   255→    processDiscoveryResources(decoded_resources, api_state, type_url, version_info,
   256→                              /*call_delegate=*/false);
   257→  }
   258→  END_TRY
   259→  CATCH(const EnvoyException& e, {
   260→    // TODO(abeyad): do something else here?
   261→    ENVOY_LOG_MISC(warn, "Failed to load config from delegate for {}: {}", source_id.toKey(),
   262→                   e.what());
   263→  });
   264→}
   265→
   266→GrpcMuxWatchPtr GrpcMuxImpl::addWatch(const std::string& type_url,
   267→                                      const absl::flat_hash_set<std::string>& resources,
   268→                                      SubscriptionCallbacks& callbacks,
   269→                                      OpaqueResourceDecoderSharedPtr resource_decoder,
   270→                                      const SubscriptionOptions& options) {
   271→  // Resource cache is only used for EDS resources.
   272→  EdsResourcesCacheOptRef resources_cache{absl::nullopt};
   273→  if (eds_resources_cache_ &&
   274→      (type_url == Config::getTypeUrl<envoy::config::endpoint::v3::ClusterLoadAssignment>())) {
   275→    resources_cache = makeOptRefFromPtr(eds_resources_cache_.get());
   276→  }
   277→  auto watch = std::make_unique<GrpcMuxWatchImpl>(resources, callbacks, resource_decoder, type_url,
   278→                                                  *this, options, local_info_, resources_cache);
   279→  ENVOY_LOG(debug, "gRPC mux addWatch for " + type_url);
   280→
   281→  // Lazily kick off the requests based on first subscription. This has the
   282→  // convenient side-effect that we order messages on the channel based on
   283→  // Envoy's internal dependency ordering.
   284→  // TODO(gsagula): move TokenBucketImpl params to a config.
   285→  if (!apiStateFor(type_url).subscribed_) {
   286→    apiStateFor(type_url).request_.set_type_url(type_url);
   287→    apiStateFor(type_url).request_.mutable_node()->MergeFrom(local_info_.node());
   288→    apiStateFor(type_url).subscribed_ = true;
   289→    subscriptions_.emplace_back(type_url);
   290→  }
   291→
   292→  // This will send an updated request on each subscription.
   293→  // TODO(htuch): For RDS/EDS, this will generate a new DiscoveryRequest on each resource we added.
   294→  // Consider in the future adding some kind of collation/batching during CDS/LDS updates so that we
   295→  // only send a single RDS/EDS update after the CDS/LDS update.
   296→  queueDiscoveryRequest(type_url);
   297→
   298→  return watch;
   299→}
