    67→template <class S, class F, class RQ, class RS>
    68→std::unique_ptr<GrpcStreamInterface<RQ, RS>> GrpcMuxImpl<S, F, RQ, RS>::createGrpcStreamObject(
    69→    Grpc::RawAsyncClientSharedPtr&& async_client,
    70→    Grpc::RawAsyncClientSharedPtr&& failover_async_client,
    71→    const Protobuf::MethodDescriptor& service_method, Stats::Scope& scope,
    72→    BackOffStrategyPtr&& backoff_strategy, const RateLimitSettings& rate_limit_settings) {
    73→  if (Runtime::runtimeFeatureEnabled("envoy.restart_features.xds_failover_support")) {
    74→    return std::make_unique<GrpcMuxFailover<RQ, RS>>(
    75→        /*primary_stream_creator=*/
    76→        [&async_client, &service_method, &dispatcher = dispatcher_, &scope, &backoff_strategy,
    77→         &rate_limit_settings](
    78→            GrpcStreamCallbacks<RS>* callbacks) -> GrpcStreamInterfacePtr<RQ, RS> {
    79→          return std::make_unique<GrpcStream<RQ, RS>>(
    80→              callbacks, std::move(async_client), service_method, dispatcher, scope,
    81→              std::move(backoff_strategy), rate_limit_settings,
    82→              GrpcStream<RQ, RS>::ConnectedStateValue::FirstEntry);
    83→        },
    84→        /*failover_stream_creator=*/
    85→        failover_async_client
    86→            ? absl::make_optional(
    87→                  [&failover_async_client, &service_method, &dispatcher = dispatcher_, &scope,
    88→                   &rate_limit_settings](
    89→                      GrpcStreamCallbacks<RS>* callbacks) -> GrpcStreamInterfacePtr<RQ, RS> {
    90→                    return std::make_unique<GrpcStream<RQ, RS>>(
    91→                        callbacks, std::move(failover_async_client), service_method, dispatcher,
    92→                        scope,
    93→                        // TODO(adisuissa): the backoff strategy for the failover should
    94→                        // be the same as the primary source.
    95→                        std::make_unique<FixedBackOffStrategy>(
    96→                            GrpcMuxFailover<RQ, RS>::DefaultFailoverBackoffMilliseconds),
    97→                        rate_limit_settings, GrpcStream<RQ, RS>::ConnectedStateValue::SecondEntry);
    98→                  })
    99→            : absl::nullopt,
   100→        /*grpc_mux_callbacks=*/*this,
   101→        /*dispatch=*/dispatcher_);
   102→  }
   103→  return std::make_unique<GrpcStream<RQ, RS>>(this, std::move(async_client), service_method,
   104→                                              dispatcher_, scope, std::move(backoff_strategy),
   105→                                              rate_limit_settings,
   106→                                              GrpcStream<RQ, RS>::ConnectedStateValue::FirstEntry);
   107→}
