   208→template <class S, class F, class RQ, class RS>
   209→void GrpcMuxImpl<S, F, RQ, RS>::removeWatch(const std::string& type_url, Watch* watch) {
   210→  updateWatch(type_url, watch, {}, {});
   211→  watchMapFor(type_url).removeWatch(watch);
