   161→// Updates the list of resource names watched by the given watch. If an added name is new across
   162→// the whole subscription, or if a removed name has no other watch interested in it, then the
   163→// subscription will enqueue and attempt to send an appropriate discovery request.
   164→template <class S, class F, class RQ, class RS>
   165→void GrpcMuxImpl<S, F, RQ, RS>::updateWatch(const std::string& type_url, Watch* watch,
   166→                                            const absl::flat_hash_set<std::string>& resources,
   167→                                            const SubscriptionOptions& options) {
   168→  ENVOY_LOG(debug, "GrpcMuxImpl::updateWatch for {}", type_url);
   169→  ASSERT(watch != nullptr);
   170→  auto& sub = subscriptionStateFor(type_url);
   171→  WatchMap& watch_map = watchMapFor(type_url);
   172→
   173→  // We need to prepare xdstp:// resources for the transport, by normalizing and adding any extra
   174→  // context parameters.
   175→  absl::flat_hash_set<std::string> effective_resources;
   176→  for (const auto& resource : resources) {
   177→    if (XdsResourceIdentifier::hasXdsTpScheme(resource)) {
   178→      auto xdstp_resource_or_error = XdsResourceIdentifier::decodeUrn(resource);
   179→      THROW_IF_NOT_OK_REF(xdstp_resource_or_error.status());
   180→      auto xdstp_resource = xdstp_resource_or_error.value();
   181→      if (options.add_xdstp_node_context_params_) {
   182→        const auto context = XdsContextParams::encodeResource(
   183→            local_info_.contextProvider().nodeContext(), xdstp_resource.context(), {}, {});
   184→        xdstp_resource.mutable_context()->CopyFrom(context);
   185→      }
   186→      XdsResourceIdentifier::EncodeOptions encode_options;
   187→      encode_options.sort_context_params_ = true;
   188→      effective_resources.insert(XdsResourceIdentifier::encodeUrn(xdstp_resource, encode_options));
   189→    } else {
   190→      effective_resources.insert(resource);
   191→    }
   192→  }
   193→
   194→  auto added_removed = watch_map.updateWatchInterest(watch, effective_resources);
   195→  if (options.use_namespace_matching_) {
   196→    // This is to prevent sending out of requests that contain prefixes instead of resource names
   197→    sub.updateSubscriptionInterest({}, {});
   198→  } else {
   199→    sub.updateSubscriptionInterest(added_removed.added_, added_removed.removed_);
   200→  }
   201→
   202→  // Tell the server about our change in interest, if any.
   203→  if (sub.subscriptionUpdatePending()) {
   204→    trySendDiscoveryRequests();
   205→  }
   206→}
