   336→  // now more SubscriptionStates.
   337→  absl::flat_hash_map<std::string, S*> all_subscribed;
   338→  absl::flat_hash_map<std::string, S*> already_called;
   339→  do {
   340→    for (auto& [type_url, subscription_state] : subscriptions_) {
   341→      all_subscribed[type_url] = subscription_state.get();
   342→    }
   343→    for (auto& sub : all_subscribed) {
   344→      if (already_called.insert(sub).second) { // insert succeeded ==> not already called
   345→        sub.second->handleEstablishmentFailure();
   346→      }
   347→    }
   348→  } while (all_subscribed.size() != subscriptions_.size());
   349→  should_send_initial_resource_versions_ = next_attempt_may_send_initial_resource_version;
   350→}
   351→
   352→template <class S, class F, class RQ, class RS>
   353→S& GrpcMuxImpl<S, F, RQ, RS>::subscriptionStateFor(const std::string& type_url) {
   354→  auto sub = subscriptions_.find(type_url);
   355→  RELEASE_ASSERT(sub != subscriptions_.end(),
   356→                 fmt::format("Tried to look up SubscriptionState for non-existent subscription {}.",
   357→                             type_url));
   358→  return *sub->second;
   359→}
   360→
   361→template <class S, class F, class RQ, class RS>
   362→WatchMap& GrpcMuxImpl<S, F, RQ, RS>::watchMapFor(const std::string& type_url) {
   363→  auto watch_map = watch_maps_.find(type_url);
   364→  RELEASE_ASSERT(
   365→      watch_map != watch_maps_.end(),
   366→      fmt::format("Tried to look up WatchMap for non-existent subscription {}.", type_url));
   367→  return *watch_map->second;
   368→}
   369→
   370→template <class S, class F, class RQ, class RS>
   371→void GrpcMuxImpl<S, F, RQ, RS>::trySendDiscoveryRequests() {
   372→  if (shutdown_) {
   373→    return;
   374→  }
   375→
   376→  while (true) {
   377→    // Do any of our subscriptions even want to send a request?
   378→    absl::optional<std::string> request_type_if_any = whoWantsToSendDiscoveryRequest();
   379→    if (!request_type_if_any.has_value()) {
   380→      break;
   381→    }
   382→    // If so, which one (by type_url)?
   383→    std::string next_request_type_url = request_type_if_any.value();
   384→    auto& sub = subscriptionStateFor(next_request_type_url);
   385→    ENVOY_LOG(debug, "GrpcMuxImpl wants to send discovery request for {}", next_request_type_url);
   386→    // Try again later if paused/rate limited/stream down.
   387→    if (!canSendDiscoveryRequest(next_request_type_url)) {
   388→      break;
   389→    }
   390→    std::unique_ptr<RQ> request;
   391→    // Get our subscription state to generate the appropriate discovery request, and send.
   392→    if (!pausable_ack_queue_.empty()) {
   393→      // Because ACKs take precedence over plain requests, if there is anything in the queue, it's
   394→      // safe to assume it's of the type_url that we're wanting to send.
   395→      //
   396→      // getNextRequestWithAck() returns a raw unowned pointer, which sendGrpcMessage deletes.
   397→      request = sub.getNextRequestWithAck(pausable_ack_queue_.popFront());
   398→      ENVOY_LOG(debug, "GrpcMuxImpl sent ACK discovery request for {}", next_request_type_url);
   399→    } else {
   400→      // Returns a raw unowned pointer, which sendGrpcMessage deletes.
   401→      request = sub.getNextRequestAckless();
   402→      ENVOY_LOG(debug, "GrpcMuxImpl sent non-ACK discovery request for {}", next_request_type_url);
   403→    }
   404→    ENVOY_LOG(debug, "GrpcMuxImpl skip_subsequent_node: {}", skipSubsequentNode());
   405→    sendGrpcMessage(*request, sub);
   406→  }
   407→  maybeUpdateQueueSizeStat(pausable_ack_queue_.size());
   408→}
   409→
   410→// Checks whether external conditions allow sending a discovery request. (Does not check
   411→// whether we *want* to send a discovery request).
   412→template <class S, class F, class RQ, class RS>
   413→bool GrpcMuxImpl<S, F, RQ, RS>::canSendDiscoveryRequest(const std::string& type_url) {
   414→  RELEASE_ASSERT(
   415→      !pausable_ack_queue_.paused(type_url),
   416→      fmt::format("canSendDiscoveryRequest() called on paused type_url {}. Pausedness is "
   417→                  "supposed to be filtered out by whoWantsToSendDiscoveryRequest(). ",
   418→                  type_url));
   419→
   420→  if (!grpcStreamAvailable()) {
   421→    ENVOY_LOG(trace, "No stream available to send a discovery request for {}.", type_url);
   422→    return false;
   423→  } else if (!rateLimitAllowsDrain()) {
   424→    ENVOY_LOG(trace, "{} discovery request hit rate limit; will try later.", type_url);
   425→    return false;
   426→  }
   427→  return true;
   428→}
   429→
   430→// Checks whether we have something to say in a discovery request, which can be an ACK and/or
   431→// a subscription update. (Does not check whether we *can* send that discovery request).
   432→// Returns the type_url we should send the discovery request for (if any).
   433→// First, prioritizes ACKs over non-ACK subscription interest updates.
   434→// Then, prioritizes non-ACK updates in the order the various types
   435→// of subscriptions were activated.
   436→template <class S, class F, class RQ, class RS>
   437→absl::optional<std::string> GrpcMuxImpl<S, F, RQ, RS>::whoWantsToSendDiscoveryRequest() {
   438→  // All ACKs are sent before plain updates. trySendDiscoveryRequests() relies on this. So, choose
   439→  // type_url from pausable_ack_queue_ if possible, before looking at pending updates.
   440→  if (!pausable_ack_queue_.empty()) {
   441→    return pausable_ack_queue_.front().type_url_;
   442→  }
   443→  // If we're looking to send multiple non-ACK requests, send them in the order that their
   444→  // subscriptions were initiated.
   445→  for (const auto& sub_type : subscription_ordering_) {
   446→    auto& sub = subscriptionStateFor(sub_type);
   447→    if (sub.subscriptionUpdatePending() && !pausable_ack_queue_.paused(sub_type)) {
   448→      return sub_type;
   449→    }
   450→  }
   451→  return absl::nullopt;
   452→}
   453→
   454→template class GrpcMuxImpl<DeltaSubscriptionState, DeltaSubscriptionStateFactory,
   455→                           envoy::service::discovery::v3::DeltaDiscoveryRequest,
   456→                           envoy::service::discovery::v3::DeltaDiscoveryResponse>;
