   466→// GrpcStreamCallbacks for GrpcMuxDelta
   467→void GrpcMuxDelta::requestOnDemandUpdate(const std::string& type_url,
   468→                                         const absl::flat_hash_set<std::string>& for_update) {
   469→  auto& sub = subscriptionStateFor(type_url);
   470→  sub.updateSubscriptionInterest(for_update, {});
